{{- $personal := false -}}
{{- $work := false -}}
{{- $headless := false -}}

{{- $hostname := .chezmoi.hostname -}}

{{- if eq .chezmoi.os "linux" -}}
{{-   if .chezmoi.kernel.osrelease | lower | contains "microsoft" -}}
{{-     $headless = true -}}
{{-   end -}}
{{- end -}}

{{- $name := "Your Name" -}}
{{- $email := "your.email@example.com" -}}
{{- $github_user := "yourusername" -}}

{{- if hasKey . "personal" -}}
{{-   $personal = .personal -}}
{{- else -}}
{{-   $personal = promptBoolOnce . "personal" "Is this a personal machine" -}}
{{- end -}}

{{- if hasKey . "work" -}}
{{-   $work = .work -}}
{{- else -}}
{{-   $work = promptBoolOnce . "work" "Is this a work machine" -}}
{{- end -}}

{{- if hasKey . "headless" -}}
{{-   $headless = .headless -}}
{{- else -}}
{{-   $headless = promptBoolOnce . "headless" "Is this a headless machine" -}}
{{- end -}}

{{- if hasKey . "name" -}}
{{-   $name = .name -}}
{{- else -}}
{{-   $name = promptStringOnce . "name" "Your full name" -}}
{{- end -}}

{{- if hasKey . "email" -}}
{{-   $email = .email -}}
{{- else -}}
{{-   $email = promptStringOnce . "email" "Your email address" -}}
{{- end -}}

{{- if hasKey . "github_user" -}}
{{-   $github_user = .github_user -}}
{{- else -}}
{{-   $github_user = promptStringOnce . "github_user" "Your GitHub username" -}}
{{- end -}}

[data]
    personal = {{ $personal }}
    work = {{ $work }}
    headless = {{ $headless }}
    hostname = {{ $hostname | quote }}
    name = {{ $name | quote }}
    email = {{ $email | quote }}
    github_user = {{ $github_user | quote }}

[data.features]
    ai_tools = true
    development = true
    gui = {{ not $headless }}

